const event = $json || {};
const rawPayload = event.payload;
const parsedPayload = typeof rawPayload === 'string'
  ? (() => { try { return JSON.parse(rawPayload); } catch(e) { return {}; } })()
  : (rawPayload || {});
const body = parsedPayload.body || parsedPayload;
const normalized = event.normalized || body.normalized || {};
const pr = body.pull_request || parsedPayload.pull_request || {};
const repoObj = body.repository || parsedPayload.repository || {};

const prNumber = pr.number || body.number || normalized.pull_request_number || event.pull_request_number || null;
const repoFullName = repoObj.full_name || normalized.repo || event.repo || repoObj.name || 'unknown_repo';
const repo = repoObj.name || String(repoFullName).split('/').pop() || 'unknown_repo';
const title = pr.title || body.title || normalized.title || 'Unknown title';
const description = pr.body || body.body || 'No description provided';
const actor = event.actor || body.sender?.login || parsedPayload.actor || 'system';
const branch = pr.head?.ref || normalized.branch || event.branch || null;
const commitSha = pr.head?.sha || normalized.commit_sha || event.commit_sha || null;
const prUrl = pr.html_url || normalized.url || event.url || null;

return [{
  json: {
    correlation_id: event.correlation_id || `crs-${Date.now()}`,
    source: event.source || 'github',
    event_type: event.event_type || normalized.event_type || 'code_review',
    actor,
    repo,
    repo_full_name: repoFullName,
    pr_number: prNumber,
    pr_url: prUrl,
    branch,
    commit_sha: commitSha,
    title,
    body: description,
    is_pr: Boolean(prNumber || pr.html_url),
    raw_event: event
  }
}];

const input = $json;
let raw = input.text ?? input.output ?? input.response ?? input.result ?? input;

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw || {});
}

raw = raw.trim().replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
const start = raw.indexOf('{');
const end = raw.lastIndexOf('}');
if (start !== -1 && end !== -1 && end > start) raw = raw.slice(start, end + 1);

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  parsed = {
    evaluation: raw,
    risk_level: 'medium',
    suggested_comment: 'No pude parsear la respuesta del modelo como JSON estricto. Revisar manualmente.',
    requires_human_approval: true,
    parse_error: error.message
  };
}

const ctx = $('Extract PR Details').item.json;
const risk = ['low', 'medium', 'high'].includes(String(parsed.risk_level || '').toLowerCase())
  ? String(parsed.risk_level).toLowerCase()
  : 'medium';

return [{
  json: {
    correlation_id: ctx.correlation_id,
    agent_role: 'Code Review Scout',
    decision_type: 'code_review',
    input_summary: `PR ${ctx.pr_number ? '#' + ctx.pr_number + ' ' : ''}${ctx.title} in ${ctx.repo_full_name}`,
    context_used: {
      source: ctx.source,
      event_type: ctx.event_type,
      actor: ctx.actor,
      repo: ctx.repo_full_name,
      pr_number: ctx.pr_number,
      pr_url: ctx.pr_url,
      branch: ctx.branch,
      commit_sha: ctx.commit_sha,
      title: ctx.title,
      body: ctx.body
    },
    evidence: {
      model_output: parsed,
      parse_error: parsed.parse_error || null
    },
    decision: {
      evaluation: parsed.evaluation || 'Sin evaluación generada',
      suggested_comment: parsed.suggested_comment || 'Revisar manualmente este PR.'
    },
    recommendation: parsed.suggested_comment || parsed.evaluation || 'Revisar manualmente este PR.',
    confidence: parsed.confidence || 0.75,
    risk_level: risk,
    requires_human_approval: Boolean(parsed.requires_human_approval || risk === 'high')
  }
}];
